// packages/database/src/db/schema/file.ts
// Drizzle table: file (generated by scripts/split-schema.ts)

import {
  pgTable,
  uniqueIndex,
  index,
  text,
  timestamp,
  integer,
  jsonb,
  type AnyPgColumn,
  fileStatus,
  fileVisibility,
} from './_shared'
import { createId } from '@paralleldrive/cuid2'

import { Article } from './article'
import { User } from './user'
import { KnowledgeBase } from './knowledge-base'
import { Organization } from './organization'

/** Drizzle table for file */
export const File = pgTable(
  'File',
  {
    id: text()
      .$defaultFn(() => createId())
      .primaryKey()
      .notNull(),
    createdAt: timestamp({ precision: 3 }).defaultNow().notNull(),
    updatedAt: timestamp({ precision: 3 }).notNull(),
    name: text(),
    hashedKey: text().notNull(),
    createdById: text().references((): AnyPgColumn => User.id, { onUpdate: 'cascade' }),
    organizationId: text()
      .notNull()
      .references((): AnyPgColumn => Organization.id, { onUpdate: 'cascade', onDelete: 'cascade' }),
    size: integer().default(0).notNull(),
    type: text(),
    meta: jsonb().default({}).notNull(),
    deletedAt: timestamp({ precision: 3 }),
    deletedById: text().references((): AnyPgColumn => User.id, { onUpdate: 'cascade' }),
    entityId: text(),
    entityType: text(),
    articleId: text().references((): AnyPgColumn => Article.id, {
      onUpdate: 'cascade',
      onDelete: 'cascade',
    }),
    knowledgeBaseId: text().references((): AnyPgColumn => KnowledgeBase.id, {
      onUpdate: 'cascade',
      onDelete: 'cascade',
    }),
    checksum: text(),
    confirmedAt: timestamp({ precision: 3 }),
    downloadCount: integer().default(0).notNull(),
    expiresAt: timestamp({ precision: 3 }),
    lastAccessedAt: timestamp({ precision: 3 }),
    status: fileStatus().default('PENDING').notNull(),
    visibility: fileVisibility().default('PRIVATE').notNull(),
  },
  (table) => [
    index('File_checksum_organizationId_idx').using(
      'btree',
      table.checksum.asc().nullsLast(),
      table.organizationId.asc().nullsLast()
    ),
    uniqueIndex('File_hashedKey_key').using('btree', table.hashedKey.asc().nullsLast()),
    index('File_organizationId_status_idx').using(
      'btree',
      table.organizationId.asc().nullsLast(),
      table.status.asc().nullsLast()
    ),
    index('File_status_expiresAt_idx').using(
      'btree',
      table.status.asc().nullsLast(),
      table.expiresAt.asc().nullsLast()
    ),
    index('File_visibility_hashedKey_idx').using(
      'btree',
      table.visibility.asc().nullsLast(),
      table.hashedKey.asc().nullsLast()
    ),
  ]
)
